// https://vitepress.dev/guide/custom-theme
import { h, nextTick, onMounted, watch, defineComponent } from 'vue'
import type { Theme } from 'vitepress'
import { useRoute } from 'vitepress'
import DefaultTheme from 'vitepress/theme'
// 引入 Fancybox 核心逻辑和样式
// import { Fancybox } from '@fancyapps/ui'
// import '@fancyapps/ui/dist/fancybox/fancybox.css'
// 引入 Viewer.js 和样式
import Viewer from 'viewerjs'
import 'viewerjs/dist/viewer.css'
import './style.css'
import { ElementPlusContainer } from '@vitepress-demo-preview/component'
import '@vitepress-demo-preview/component/dist/style.css'
import XElement from 'xb-element'
import './custom.css'
import * as Sentry from '@sentry/vue'

export default {
  extends: DefaultTheme,
  enhanceApp({ app }) {
    app.use(XElement)
    if (typeof window !== 'undefined') {
      // 这样 Vite 会把它单独打包成一个异步 chunk，绝不阻塞首屏渲染 (FCP)
      import('xb-element/dist/x-element.css')
      if (import.meta.env.PROD) {
        // 或者用 !import.meta.env.DEV
        console.log('🚀 生产环境，Sentry 性能监控已启动')
        // 关键：仅在浏览器环境下初始化 Sentry，防止破坏 Node.js 端的构建过程
        Sentry.init({
          app,
          dsn: 'https://b288271c3fd985d21205cbd7e36e3a43@o4511569356718080.ingest.us.sentry.io/4511569367269376', // 替换为你的 DSN
          integrations: [
            // 捕获路由切换的性能数据
            Sentry.browserTracingIntegration(),
            // 录制用户操作，方便复现复杂问题
            Sentry.replayIntegration(),
          ],
          tracesSampleRate: 0.1, // 性能监控只采集 10% 的用户数据
          replaysSessionSampleRate: 0, // 关闭正常用户的录屏采集
          replaysOnErrorSampleRate: 1.0, // 只在发生错误时才录制 1 次回放
        })
      } else {
        console.log('⚡ 本地开发环境，Sentry 已安全阻断')
      }
    }
    // 👇 注册一个自定义的高阶组件代替直接注册 ElementPlusContainer
    app.component(
      'demo-preview',
      defineComponent({
        name: 'DemoPreview',
        // 1. 改为对象声明，让 TS 能够精确推导 props 类型
        props: {
          suffixName: { type: String, default: '' },
          absolutePath: { type: String, default: '' },
          relativePath: { type: String, default: '' },
        },

        // 2. 此时 props 已经被完美推导，不再是 any
        setup(props, { attrs, slots }) {
          return () => {
            // 3. 使用 as any 断言 attrs，绕过 h 函数极其严格的泛型校验
            // 因为 attrs 本身就是透传属性，我们在运行时保证它的安全即可
            return h(ElementPlusContainer, attrs as any, slots)
          }
        },
      }),
    )
  },
  //Fancybox:图片放大库
  /* setup() {
                const route = useRoute()

                const initFancybox = () => {
                    // 绑定所有的 Markdown 图片
                    Fancybox.bind('.vp-doc img', {
                        // 开启滚轮缩放功能 (默认其实也是开启的)
                        wheel: 'zoom',
                        // 隐藏不需要的 UI 按钮 (保持 VitePress 的极简风格)
                        Toolbar: {
                            display: {
                                left: [],
                                middle: ['zoomIn', 'zoomOut', 'toggle1to1'],
                                right: ['close'],
                            },
                        },
                        // 移除多余的图片底部提示信息
                        Caption: false,
                    })
                }

                onMounted(() => {
                    initFancybox()
                })

                // 监听路由变化，切换页面后重新绑定
                watch(
                    () => route.path,
                    () => nextTick(() => initFancybox())
                )
            },*/
  setup() {
    const route = useRoute()
    let viewer: Viewer | null = null

    const initViewer = () => {
      // 销毁旧实例，防止内存泄漏
      if (viewer) {
        viewer.destroy()
      }

      // 获取当前页面的文章内容容器
      const docContainer = document.querySelector('.vp-doc')
      if (docContainer) {
        // Viewer.js 会自动寻找容器内的所有 img 标签并绑定事件
        viewer = new Viewer(docContainer as HTMLElement, {
          inline: false, // 模态框模式
          button: true, // 显示右上角关闭按钮
          navbar: false, // 隐藏底部的图库缩略图导航 (如果你只需单图放大)
          title: false, // 隐藏图片标题
          toolbar: true, // 显示底部工具栏 (包含放大/缩小/旋转等)
          tooltip: true, // 缩放时显示百分比提示
          movable: true, // 允许拖拽平移
          zoomable: true, // 允许滚轮缩放
        })
      }
    }

    onMounted(() => {
      initViewer()
    })

    watch(
      () => route.path,
      () => nextTick(() => initViewer()),
    )
  },
} satisfies Theme
